var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래서, 생명에 지장은 없는 건가?","JPN":"それで、命に別状はないのか？","ENG":"So, is he going to live?","TWN":"所以，沒有生命危險嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그렇다니까. 피를 너무 많이 흘려서 기절한 거래.","JPN":"そうよ。血を流しすぎたせいで気絶したんだって。","ENG":"Yeah. He just fainted because he lost a lot of blood.","TWN":"是的，就是失血過多暈過去了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"수술은 잘 끝났어. 부상이 다 나을 때까지 안정만 잘 취하래.","JPN":"手術は無事に終わったから、怪我が治るまで安静にしていればいいらしいわ。","ENG":"The surgery went well. The doc wants you to rest until your wounds heal.","TWN":"手術結束了。在傷口痊癒之前要好好休息。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐, 확실히 정규군의 의료 수준은 다르더군.","JPN":"まぁ、正規軍の医療レベルはそこらのものとは確かに違ったな。","ENG":"The standard of medical care is on another level in the army, you know?","TWN":"嗯，正規軍的醫療水準確實不一樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"저 녀석, 매번 죽을 짓을 하는데도 용케 살아난다니까.","JPN":"あいつ、毎回命知らずなことをやるのに、なぜか生き延びるんだよな。","ENG":"Him again. He always somehow survives after putting himself at the brink of death.","TWN":"那傢伙，每次做了會死的事都能活下來。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"휘말리는 우리 입장도 좀 생각해 주라고.","JPN":"それに巻き込まれる俺たちの身にもなってほしいぜ。","ENG":"Think about how that makes us look, all right?","TWN":"拜託你也想想捲入其中的我們的立場。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"맞아. 이번에는 정말 아찔했다고.","JPN":"まったくだ。今回は本当にヒヤッとしたぜ。","ENG":"Yeah. It was a close one this time.","TWN":"沒錯，這次真的很驚險。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"후후, 행운의 여신도 가끔은 새침할 때가 있는 거지.","JPN":"ハハッ、幸運の女神もたまには意地悪になるってことさ。","ENG":"Ha ha, Lady Luck can be moody sometimes.","TWN":"哈哈，幸運女神也會有心情不好的時候。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"으억!","JPN":"うおっ！","ENG":"Gwuh!","TWN":"呃！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL"},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭘 웃어! 누군 죽은 줄 알고 심장 떨어질 뻔했는데!","JPN":"何がハハ、よ！　死んだと思って心臓止まるかと思ったのに！","ENG":"What are you laughing about? We were worried sick that you might not make it!","TWN":"你笑什麼！我還以為有人死了，心臟差點掉出來！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"때, 때려도 하필 다친 데를…….","JPN":"き、傷があるところを殴るなんて……","ENG":"Y-you just had to hit me where it hurts the most...","TWN":"為，為什麼偏偏打受傷的地方……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐? 미, 미안! 괜찮아? 많이 아파?","JPN":"え？　ご、ごめん！　大丈夫？　痛かった？？","ENG":"What? S-sorry! You okay? Does it hurt a lot?","TWN":"什麼？對，對不起！你沒事吧？很疼嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……괜찮아 보여서 다행이군.","JPN":"……大事に至らずなによりだ。","ENG":"...Good to see you back on your feet.","TWN":"……幸好看起來沒事。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"등대는 어떻습니까, 회장님.","JPN":"灯台はどうなりましたか、会長。","ENG":"Miss Shin, what happened to the Lighthouse?","TWN":"燈塔怎麼樣了，會長。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"펑 터져 버려서 수리는 불가능하겠어요. 새로 만드는 편이 더 빠르겠네요.","JPN":"爆発で完全に壊れてしまって、修理は無理ですね。新しく建て直した方が早いというか。","ENG":"It exploded beyond repair. It would be faster to construct a new one.","TWN":"爆炸了，修理是不可能的了。也許建個新的會更快。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"일말의 여지도 없이 시원하게 대답하시는군요.","JPN":"スパッと言い切りますね。","ENG":"You answered without any hesitation.","TWN":"回答得真是乾脆，一點轉圜的餘地都沒有呢。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그럼 새로 만든다고 하면 얼마나 걸릴 것 같습니까?","JPN":"では新しく建てるとしたら、どのくらいかかりそうでしょうか？","ENG":"Then how long would it take to build a new one?","TWN":"那如果建個新的，大概需要多長時間？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"글쎄요. 기초 기술부터 세대가 달라서, 생산을 위한 인프라까지 감안하면……","JPN":"そうですね。全然違う世代の基礎技術が使われているし、生産に必要なインフラのことも考えたら……","ENG":"I'm not sure. But given the difference in technology, and the infrastructure needed...","TWN":"這個嘛。考慮到基本技術碾壓式的差距，還有生產需要用的基礎設施……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"30년 정도 아닐까요?","JPN":"30年ぐらいはかかるんじゃないでしょうか？","ENG":"Perhaps it'll take about 30 years or so?","TWN":"大概30年左右吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……구 관리국 상대로 그런 현실적인 숫자가 나오는 건 대단하지만, 역시 까마득하군요.","JPN":"……旧管理局のものを相手に、そうやって現実的な試算ができるのはすごいですが、やはり途方もありませんね。","ENG":"...I am impressed that you came up with a realistic number against the Old Administration, but that is too far away.","TWN":"……以舊管理局為對手，出來這個時間已經很厲害了，不過還真是遙遠啊。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"첩보에 따르면 회장님의 능력은 물질 생성도 가능할 텐데요.","JPN":"情報によれば、会長の能力は物質生成も可能だそうですが。","ENG":"I recall that you are able to create matter with your ability, Miss Shin.","TWN":"根據情報，會長的能力還可以生成物質。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그 힘으로 해결할 수는 없는 겁니까?","JPN":"その力でなんとかならないのでしょうか？","ENG":"Is there a way to use that power to resolve this?","TWN":"不能用那種力量解決嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그럼 아마 완성에 다다르기 전에 제 인격이 먼저 마모될 거예요.","JPN":"それをやると完成に至る前に、私の人格がすり減ってしまうでしょう。","ENG":"If I do, my humanity will deteriorate before it is complete.","TWN":"那樣或許在完成之前，我的人格就會先毀滅。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그렇게 된 상태에서 여러분을 도울 거라는 장담은 드릴 수 없으니까요. 죄송해요.","JPN":"そうなってからでは、皆さんのお役に立てるかどうかわかりませんので。すみません。","ENG":"Then, I cannot say how much of a help I would be for everyone, so I would prefer not to.","TWN":"在那種狀態下，我也不能保證自己能幫到大家。對不起。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"아, 아닙니다. 저야말로 도가 지나친 부탁을 드렸습니다.","JPN":"と、とんでもありません。こちらこそ無理を言ってすみませんでした。","ENG":"Oh, my apologies. That was rude of me to ask.","TWN":"不，不是的。是我的請求過分了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"저……. 다른 등대를 찾아 보면 어떨까요?","JPN":"あの……他の灯台を探してみるのはどうでしょうか？","ENG":"Um... How about trying to find another Lighthouse?","TWN":"那個……找找其他燈塔怎麼樣？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"등대가 꼭 하나만 있으리라는 법은 없잖아요.","JPN":"灯台が一基しかないと決まったわけでもありませんし。","ENG":"It's not like that was the only one in existence, right?","TWN":"不一定只有一個燈塔啊。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"여긴 이면세계도 아니고 허수공간이야. 하나라도 남아 있는 게 용하지.","JPN":"ここは裏世界じゃなく虚数空間なんだ。一基でも残っていたのは奇跡さ。","ENG":"We're not in Counterside. This is the imaginary space. And we were extremely lucky to even have one.","TWN":"這裡不是異界，而是虛數空間。能剩下一個就不錯了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그 구 관리국이란 놈들이 언제 사라졌는데?","JPN":"それに、その旧管理局という連中が消えたのがいつだと思ってんだ？","ENG":"So when did these Old Administration people disappear anyway?","TWN":"你們想想舊管理局的那些傢伙是什麼時候消失不見的？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"애초에 허수 공간을 자력으로 탈출한다는 게 도박이긴 했어.","JPN":"そもそも虚数空間を自力で抜け出そうなんて、相当な賭けだった。","ENG":"It was a gamble to try to escape the imaginary space on our own in the first place.","TWN":"靠自己的力量逃出虛數空間，從一開始就是一場豪賭。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"아쉽지만 그 등대가 우리의 유일한 희망이었단 소리지.","JPN":"残念だが、あの灯台が俺たちにとっての唯一の希望だったというわけだ。","ENG":"And unfortunately, that Lighthouse was our only hope.","TWN":"可惜那個燈塔是我們唯一的希望。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"면목없습니다, 사령관님. 저희가 조금만 더 분발했더라면…….","JPN":"面目ありません、司令官。俺たちがもう少し頑張っていれば……","ENG":"We've failed you, Commander. If only we tried a little harder...","TWN":"實在抱歉，司令官。要是我們再多努力一點……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자네답지 않은 소리 말게, 대령.","JPN":"君らしくないぞ、大佐。","ENG":"Don't beat yourself up, Colonel.","TWN":"這是什麼話，一點都不像你，上校。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"우리는 지금 전쟁 중이야. 나는 책임 소재를 물을 시간에 활로를 찾고 싶네.","JPN":"今は戦争中だ。責任の所在を明らかにする暇があるなら、活路を模索したい。","ENG":"We are at war. I would rather look for a solution than point fingers at whose fault it was.","TWN":"我們現在是在打仗。比起追究責任，我更想用那個時間尋找活路。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"방법은 있다.","JPN":"方法はある。","ENG":"There is another possibility.","TWN":"我有辦法。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"방금 뭐라고 했나? 방법이 있다고?","JPN":"今なんと？　方法があるって？","ENG":"What did you say? You know how to get out of here?","TWN":"你剛剛說什麼？你有辦法？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"공간 좌표 계산은 내 특기다.","JPN":"空間座標の計算は私の得意分野だ。","ENG":"Calculating space coordinates is my specialty.","TWN":"計算空間座標是我的專長。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"등대의 메커니즘은 알 수 없지만, 등대에서 방출되는 신호가 어떻게 좌표를 포착하는지는 파악했다.","JPN":"灯台のメカニズムはわからないが、灯台から放出される信号がどのように座標を捉えるのかは特定できた。","ENG":"The mechanism of the Lighthouse is unclear, but I have figured out how the Lighthouse's signal is converted into coordinates.","TWN":"雖然不知道燈塔的原理，但我已經掌握燈塔釋放的訊號是如何捕捉座標的了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그럼 클리파 차원으로 가는 길잡이가 되어 주실 수 있다는 건가요?","JPN":"それはクリファ次元まで案内できるということですか？","ENG":"Are you saying you'll be our pathfinder to Qlipha Dimension?","TWN":"那也就是說，你能當前往逆卡巴拉次元的導遊嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"가능하다. 함선의 신호 발산 영역 내에서는.","JPN":"可能だ。艦船の信号発散の領域内なら。","ENG":"That is possible. But only within the ship's signal transmission range.","TWN":"在艦船的訊號發射區域內，就可以。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"당신이 공간 좌표 계산에 능숙하다는 건 지난 전투에서 확인했습니다.","JPN":"あなたが空間座標の計算に長けているのは以前の戦闘で確認しました。","ENG":"I have already seen that you excel in calculating space coordinates from our last battle.","TWN":"你很擅長計算空間座標這件事，在上次的戰鬥中就已經見識過了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"하지만 여긴 허수 공간입니다. 함선의 시스템도 소화하지 못하는 연산량을 혼자 감당할 수 있다는 겁니까?","JPN":"しかしここは虚数空間内です。艦船のシステムでも消化しきれない演算量を一人で負担できるんですか？","ENG":"However, we are in the imaginary space. Do you really believe you can perform all of the calculations that the ship's system could not?","TWN":"不過這裡是虛數空間。艦船的系統都消化不了的運算量，你一個人能承受得了嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"나는 본래 테라사이드 계획에서 이면세계 이민선단의 중추로 활용하기 위해 확보되었다.","JPN":"私は本来テラサイドプロジェクトにおいて裏世界に向かう移民船団の中枢として活用される予定だった。","ENG":"In the original Terraside plan, I was secured to serve as the core of the Counterside immigration fleet.","TWN":"我本來就是在特拉賽德計畫中，作為異界移民艦隊的中樞而創造出來的。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"선단 운용을 위해 마련된 연산 능력을 최대한으로 활용한다면, 불가능은 아니다.","JPN":"船団の運用のために設けられた演算能力を最大限発揮すれば、不可能ではない。","ENG":"If I utilize my calculating abilities designed to operate the fleet, it is not impossible.","TWN":"如果能最大化地利用為艦隊而準備的運算力，也並非不可能。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"그러니까…… 네가 등대 대신 길을 찾을 수 있다고?","JPN":"つまり……お前が灯台の代わりにルートを検索できるってこと？","ENG":"So... You're saying you can find a way without the Lighthouse?","TWN":"所以……你能代替燈塔找到路？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"하지만 신호에 반응해서 나타날 침식체들은? 그것들까지는 어쩌지 못할 텐데?","JPN":"でも信号に反応して現れる侵食体は？　それはどう解決するの？","ENG":"Then what about the C.O.s that will react to the signal? I'm sure you can't do anything about that.","TWN":"但是對訊號做出反應而出現的侵蝕體呢？對那些應該沒辦法吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That’s...","TWN":"那個……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"저희 몫입니다.","JPN":"それは私たちの役目でしょう。","ENG":"That's where we come in.","TWN":"我們負責解決。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"여기 있는 승조원들은 전부 리플레이서 전역 때부터 함께 해 온 베테랑들입니다.","JPN":"ここの乗組員たちは全員、リプレイサー戦域を共に生き抜いたきたベテランたちです。","ENG":"Everyone on this ship is a veteran combatant who has been together since the Replacer battle.","TWN":"這裡的艦上人員全都是從克隆集團戰役時就開始一直並肩作戰的老兵。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"맡겨 주십시오. 반드시 해내겠습니다.","JPN":"任せてください。必ずやってみせます。","ENG":"Leave it to us. We'll take care of them.","TWN":"交給我們吧，我們一定會做到。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"넘버 5가 활약하겠다는데 우리도 가만히 있을 수야 없지.","JPN":"ナンバー5が活躍すると言っているんだ、私たちもじっとしているわけにはいかないな。","ENG":"We can't sit around and let number 5 have all the fun.","TWN":"5號都說要參與了，我們當然也不能袖手旁觀。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"맞아! 이 기회에 우리 이름을 온 세상에 널리 알리자고!","JPN":"そうよ！　これを機に私たちの名を世界中に轟かせよう！","ENG":"Yeah! Let's use this opportunity to spread our name!","TWN":"沒錯！借此機會讓全世界都知道我們的名字吧！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"어둠의 정보전사라면서 공공연하게 유명세를 퍼뜨릴 작정인가?","JPN":"闇の情報戦士を名乗っているのに、表世界で有名になるのか？","ENG":"You call yourselves the Info Warriors of Darkness, and yet you want to become publicly famous?","TWN":"你是想讓黑暗中的資訊戰士走到人前嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"……나쁘지 않군. 재밌겠어.","JPN":"……悪くない。面白そうだ。","ENG":"...Not bad. Sounds like fun.","TWN":"……也不錯，一定很有趣。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"좋아. 이견은 없는 것 같으니 바로 출발하도록 하지.","JPN":"よし、反対意見はないようだし、さっそく出発しよう。","ENG":"All right. Looks like there are no objections, so we get moving.","TWN":"好了，既然都沒有異議，那就馬上出發吧。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"모두의 목숨을 부탁하겠네. 부디 길을 찾아 주게나.","JPN":"皆の命を頼んだ。どうかルートを見つけてくれ。","ENG":"I am putting everyone's lives in your hands. So please find a way out of here.","TWN":"所有人的命就都交給你了。拜託你一定要找到路。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"부탁할 필요 없다. 인류의 보존에 기여하는 건 내가 태어난 의미이기도 하니까.","JPN":"お願いの必要はない。人類の保存に寄与するのは、私が生まれた理由でもある。","ENG":"No need to ask. I was born with the purpose of contributing to the preservation of humankind.","TWN":"不需要拜託我。為保護人類作出貢獻也是我誕生的意義。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"성공하겠다. 반드시.","JPN":"成功してみせる。必ずだ。","ENG":"You have my word. I will not fail.","TWN":"我會成功的，一定。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};